cd C:/work/mega/astramemory-plugin && node -e "
const http = require('node:http');
const { spawnSync } = require('node:child_process');
const calls = { count: 0 };
const srv = http.createServer((req, res) => {
  calls.count++;
  console.log('GOT', req.method, req.url);
  req.on('data', () => {});
  req.on('end', () => { res.writeHead(503).end('{}'); });
});
srv.listen(0, '127.0.0.1', () => {
  const port = srv.address().port;
  console.log('PORT=', port);
  const r = spawnSync('curl', ['-sS', '-w', '%{http_code}', '-X', 'POST', \`http://127.0.0.1:\${port}/ingest/transcript\`, '-d', ''], { encoding: 'utf-8' });
  console.log('CURL STATUS', r.status);
  console.log('CURL STDOUT', JSON.stringify(r.stdout));
  console.log('CURL STDERR', r.stderr);
  console.log('CALLS', calls.count);
  srv.close();
});
"
